let switch_value = null;

try {
  switch_value = $('Switch').first().json.data["Ready to proceed to next step ?"];
} catch (e) {
  // Node possibly unexecuted; leave as null
}

if (String(switch_value).trim().toLowerCase() == 'Provide Feedback' ) {
  $input.first().json.text = "*📰 AI Generated Themes for Review with User feedback*";
}

const themes = $input.first().json.themes;

// Build the options list
const options = themes.map(theme => ({
  option: "THEME: " + theme.theme
}));

// Add the static final option
options.push({ option: "Add Feedback" });

// Make a form.
$input.first().json.approve_form = [
  {
    fieldLabel: "Newsletter Theme or Feedback",
    fieldType: "radio",
    fieldOptions: {
      values: options
    }
  },
  {
    "fieldLabel": "Editor Feedback for AI",
    "fieldType": "textarea"
  }
];

return $input.all();

// Build values.
const theme = $('Format theme output').first().json.selected_theme_title.replace(/'/g, "''"); // escape single quotes in text
const theme_body = $('Format theme output').first().json.selected_theme.theme_body.replace(/'/g, "''"); // escape single quotes in text
const theme_summary = $('Format theme output').first().json.selected_theme.theme_summary.replace(/'/g, "''"); // escape single quotes in text

// Create default newsletter_id.
const newsletter_id = "";


try {
  newsletter_id = $('Format theme output').first().json.summaries[0].json.newsletter_id;
} catch (e) {
  // Node possibly unexecuted; leave as null
}

if (newsletter_id && newsletter_id == "") {
  const now = $now; // $now is a Luxon DateTime object in n8n
  const formattedDate = now.toFormat('ddMMyyyy');
  const newsletter_id = `N${formattedDate}`;
}

const approved = 'TRUE';  
const values = `('${theme}', '${theme_body}', '${theme_summary}', '${newsletter_id}', ${approved} ,CURRENT_TIMESTAMP)`;

// Combine everything into a single safe SQL statement  ,\n
const query = `
INSERT INTO newsletter_themes (theme, theme_body, theme_summary, newsletter_id, approved, created_at)
VALUES
  ${values}
ON CONFLICT (theme)
DO UPDATE SET
  theme_body = EXCLUDED.theme_body,
  theme_summary = EXCLUDED.theme_summary,
  newsletter_id = EXCLUDED.newsletter_id,
  created_at = CURRENT_TIMESTAMP;
`;

return [
  {
    json: { query: query.trim() }
  }
];

const input = $input.first().json.output.data;

const parts = input
  .split('-----')
  .map(p => p.trim())
  .filter(p => p.length > 0);

function extractTheme(block, filter) {

  // Match THEME Summary: value (up to end of line)
  if (filter == "summary") {
    const match = block.match(/Theme Description\s*:\s*(.+)/i);
    return match ? match[1].trim() : null;    
  }

  // Match THEME: value (up to end of line)
  const match = block.match(/THEME\s*:\s*(.+)/i);
  return match ? match[1].trim() : null; 
}

// Collect block that contain THEME
const recommendation = parts.filter(block =>
  block.includes("RECOMMENDATION:")
);

// Collect blocks that contain RECOMMENDATION
const themes_raw = parts.filter(block =>
  !block.includes("RECOMMENDATION:")
);

// Build array of objects from the filtered blocks
const result = themes_raw.map(block => ({
  theme: extractTheme(block, "theme"),
  theme_summary: extractTheme(block, "summary"),
  theme_body: block
}));

return [{
  "themes" : result,
  "recommendation" : recommendation,  
}];

return result;

const themes = $input.first().json.themes;
const recommendation = $input.first().json.recommendation;
const combinedText = `*📰 AI Generated Themes for Review*`;

// Prepare and format themes output.
function formatTheme(block) {

  block = block.replaceAll(/^%[A-Za-z0-9]{2}_URL[^\r\n]*\r?\n?/gm, "");
  block = block.replaceAll(/^%[A-Za-z0-9]{2}_RATIONALE[^\r\n]*\r?\n?/gm, "");
  block = block.replaceAll(/^%[A-Za-z0-9]{2}_ORIGIN[^\r\n]*\r?\n?/gm, "");
  block = block.replaceAll(/^%FA_TITLE:?/gm, "• *Featured Candidate:* ");
  block = block.replaceAll(/\n%FA_SOURCE:?/gm, "  (Source ");
  block = block.replaceAll(/\n%FA_CATEGORY:?/gm, ") - ");
  block = block.replaceAll(/\nFEATURED ARTICLE:?/gm, "");
  block = block.replaceAll(/\n%FA_WHY FEATURED:?/gm, " - ");
  block = block.replaceAll(/^%M1_TITLE:?/gm, "• *Main Candidate 1:* ");
  block = block.replaceAll(/\n%M1_SOURCE:?/gm, "  (Source ");
  block = block.replaceAll(/\n%M1_CATEGORY:?/gm, ") - ");
  block = block.replaceAll(/^%M2_TITLE:?/gm, "• *Main Candidate 2:* ");
  block = block.replaceAll(/\n%M2_SOURCE:?/gm, "  (Source ");
  block = block.replaceAll(/\n%M2_CATEGORY:?/gm, ") - ");
  block = block.replaceAll(/^%Q1_TITLE:?/gm, "\n• *Quick Hits Candidates:* \n  •");
  block = block.replaceAll(/\n%Q1_SOURCE:?/gm, "  (Source ");
  block = block.replaceAll(/\n%Q1_CATEGORY:?/gm, ") - ");
  block = block.replaceAll(/^%Q2_TITLE:?/gm, "  •");
  block = block.replaceAll(/\n%Q2_SOURCE:?/gm, "  (Source ");
  block = block.replaceAll(/\n%Q2_CATEGORY:?/gm, ") - ");
  block = block.replaceAll(/^%Q3_TITLE:?/gm, "  •");
  block = block.replaceAll(/\n%Q3_SOURCE:?/gm, "  (Source ");
  block = block.replaceAll(/\n%Q3_CATEGORY:?/gm, ") - ");
  block = block.replaceAll(/^%I1_TITLE:?/gm, "\n• *Industry Candidates:* \n  •");
  block = block.replaceAll(/\n%I1_SOURCE:?/gm, "  (Source ");
  block = block.replaceAll(/\n%I1_Major AI Player:?/gm, ") - ");
  block = block.replaceAll(/^%I2_TITLE:?/gm, "  •");
  block = block.replaceAll(/\n%I2_SOURCE:?/gm, "  (Source ");
  block = block.replaceAll(/\n%I2_Major AI Player:?/gm, ") - ");
  block = block.replaceAll(/^2-2-2 Distribution:?/gm, "\n *2-2-2 Distribution*");
  block = block.replaceAll(/%222_tactical:%?/gm, "  • *Tactical:* ");
  block = block.replaceAll(/%222_educational:%?/gm, "  • *Educational:* ");
  block = block.replaceAll(/%222_forward-thinking:%?/gm, "  • *Forward-thinking:* ");
  block = block.replaceAll(/^2-2-2 Distribution:?/gm, "\n*2-2-2 Distribution:*");
  block = block.replaceAll(/%222_tactical:%?/gm, "  • *Tactical:* ");
  block = block.replaceAll(/%222_educational:%?/gm, "  • *Educational:* ");
  block = block.replaceAll(/%222_forward-thinking:%?/gm, "  • *Forward-thinking:* ");
  block = block.replaceAll(/%SM_smaller_publisher:%?/gm, "  • *Smaller Publisher:* ");
  block = block.replaceAll(/%SM_major_ai_player_coverage:%?/gm, "  • *Major AI Player Coverage:* ");
  block = block.replaceAll(/REQUIREMENTS VERIFIED[^\r\n]*\r?\n?/gm, "");
  block = block.replaceAll(/^%RV_Major AI player coverage:[^\r\n]*\r?\n?/gm, "");
  block = block.replaceAll(/^%RV_Technical complexity:[^\r\n]*\r?\n?/gm, "");
  block = block.replaceAll(/^%RV_Source mix:[^\r\n]*\r?\n?/gm, "");
  block = block.replaceAll(/^%RV_2-2-2 Distribution Achieved:[^\r\n]*\r?\n?/gm, "");
  block = block.replaceAll(/Source mix:/gm, "*Source mix:* ");  
  block = block.replaceAll(/%[A-Za-z0-9]{2}_/gi, "");
  block = block.replaceAll(/^THEME[^\r\n]*\r?\n?/gm, "");
  block = block.replaceAll(/^Theme Description:?/gm, "*Core Narrative:*");
  block = block.replaceAll(/^Articles that fit.?/gm, "\n*Articles that fit:*");
  return block; 
}

// Prepare and format recommendation output.
function formatRecommendation(text) {
  let toFormatText = String(text ?? '');
  toFormatText = toFormatText.replaceAll(/Rationale:/g, "*Rationale:*");
  toFormatText = toFormatText.replaceAll(/(RECOMMENDATION:\s*)([^\n]+)/g, '$1*$2*');
  toFormatText = toFormatText.replaceAll(/(\d+\.\s*)(.+?)(?=:\s|- )/g, '$1*$2*');
  toFormatText = toFormatText.replaceAll(/%[A-Za-z0-9]{2}_/gi, "");
  toFormatText = toFormatText.replaceAll(/%222_/gi, "");

  return toFormatText; 
}

const blocks = [
  {
    type: "section",
    text: {
      type: "mrkdwn",
      text: `\n* Newsletter Text Themes: *\n`
    }
  },
  { type: "divider" },
    ...themes.flatMap((a, index) => [
    {
      type: "section",
      text: {
        type: "mrkdwn",
        text:
          `*THEME ${index + 1}:* *${a.theme}*\n\n` +
          `\n${formatTheme(a.theme_body)}\n\n`
      }
    },
    { type: "divider" },
  ]),
  {
    type: "section",
    text: {
      type: "mrkdwn",
      text: `\n${formatRecommendation(recommendation)}\n`
    }
  },
];

let message = blocks
  .map(b => b.text?.text || '')
  .filter(Boolean)
  .join('\n──────────────────────────────\n\n');

return [
  {
    json: {
      text: combinedText, // fallback full text
      blocks,             // structured Slack Block Kit
      message, // flattened message for "Send message and wait for response"
      themes: themes
    }
  }
];

// --- Get Initial Data ---
const combinedText = `*📰 AI Generated Themes for Review*`;
let freshFeedback = null;
let inputChatData = '';
let inputChatDataSummary = [];
let resetTriggered = null;
let inputData = [];

try {
  inputData = $('Workflow Initiated').all();
} catch (error) {}

let inputSummaries = inputData;

// Check if we have input from the chat.
try {
  inputChatData = $('When chat message received').first().json.chatInput;
  inputChatDataSummary = JSON.parse(inputChatData);
} catch (error) {}

// Take summaries from the Chat input

if (Array.isArray(inputChatDataSummary) && inputChatDataSummary.length > 0 && inputChatDataSummary[0]?.newsletter_id !== '' ) {
  inputSummaries = inputChatDataSummary;
}

// --- Gather all feedback entries ---
const feedbackArray = $input.all()
  .map(item => item.json.feedback_text)
  .filter(f => f && f.trim() !== '');

// --- Combine feedback into a bullet-style list ---
let aggregatedFeedback = feedbackArray.length
  ? feedbackArray.map(f => `• ${f}`).join('\n')
  : '';

// --- Inject fresh user feedback
try {
  freshFeedback = $('Switch').first().json.data["Editor Feedback for AI"];
} catch (e) {}

if (freshFeedback && freshFeedback !== '') {
  aggregatedFeedback = '\n• ' + freshFeedback + '\n'
}

// --- Check if reset was triggered.
try {
  resetTriggered = $input.first().json.data["Approve or Feedback"];
} catch (e) {}

// If the Reset was triggered - clear all feedbacks.
if (resetTriggered && resetTriggered !== '') {
  aggregatedFeedback = '';
}

return [
  {
    json: {
      text: combinedText,
      aggregatedFeedback: aggregatedFeedback,
      summaries: inputSummaries,
    }
  }
];

// Init
const themes = $('Conditional output').first().json.themes;
const userSelectedTheme = $('Switch').first().json.data["Newsletter Theme or Feedback"];
const inputData = $('Process User Feedback').first().json.summaries;

const inputSummaries = inputData || [];
let selected_theme = null;
const checkAIFeedback = '';

// Loop through array and separate
for (var theme of themes) {
  const theme_name_formatted = "THEME: "+theme.theme;
  if (theme_name_formatted == userSelectedTheme) {
    selected_theme = theme;
  }
}

// Check if we have processed feedback loop.
try {
  const checkAIFeedback = $('Learning data extractor - theme approve').first().json.output.data;
} catch (e) {
  // Node possibly unexecuted; leave as null
}

if (checkAIFeedback && checkAIFeedback !== '') {
  selected_theme.theme_body = checkAIFeedback;
}

return [
  {
    "selected_theme_title" : userSelectedTheme,
    "selected_theme" : selected_theme,
    "summaries" : inputSummaries
  }
];

